#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e6 + 3;
ll n, k, a[MAXN];
ll l, r;
bool check(int x)
{
	ll S = 0;
	for (int i = 1; i <= n; ++i)
	{
		int t = a[i] - x;
		if (t <= 0)S += 1 - t;
	}
	return S <= k * x;
}
int main(void)
{
	cin >> n >> k;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
		r += a[i];
	}
	l = 0;
	ll mid, ans;
	while (l <= r)
	{
		mid = (l + r)/2;
		if (check(mid))
		{
			ans = mid;
			l = mid + 1;
		}
		else r = mid - 1;
	}
	cout << ans;
	return false;
}
